  1→/**
  2→ * Gateway Protocol test helpers for acceptance tests.
  3→ *
  4→ * Provides WebSocket connection management, protocol frame helpers,
  5→ * event collection utilities, and data seeding for testing the Gateway Protocol v3.
  6→ */
  7→import { RecordId, type Surreal } from "surrealdb";
  8→
  9→// --- Protocol Frame Types ---
 10→
 11→export type RequestFrame = {
 12→  readonly type: "req";
 13→  readonly id: string;
 14→  readonly method: string;
 15→  readonly params?: unknown;
 16→};
 17→
 18→export type ResponseFrame =
 19→  | {
 20→      readonly type: "res";
 21→      readonly id: string;
 22→      readonly ok: true;
 23→      readonly payload?: unknown;
 24→    }
 25→  | {
 26→      readonly type: "res";
 27→      readonly id: string;
 28→      readonly ok: false;
 29→      readonly error: { code: string; message: string; details?: unknown };
 30→    };
 31→
 32→export type EventFrame = {
 33→  readonly type: "event";
 34→  readonly event: string;
 35→  readonly payload?: unknown;
 36→  readonly seq?: number;
 37→};
 38→
 39→export type GatewayFrame = RequestFrame | ResponseFrame | EventFrame;
 40→
 41→// --- Gateway Test Client ---
 42→
 43→export type GatewayTestClient = {
 44→  /** Send a request frame and wait for the matching response */
 45→  readonly request: (
 46→    method: string,
 47→    params?: unknown,
 48→  ) => Promise<ResponseFrame>;
 49→  /** Collect event frames until predicate returns true or timeout */
 50→  readonly collectEvents: (
 51→    predicate: (event: EventFrame) => boolean,
 52→    timeoutMs?: number,
 53→  ) => Promise<readonly EventFrame[]>;
 54→  /** Wait for a single event matching a predicate */
 55→  readonly waitForEvent: (
 56→    predicate: string | ((event: EventFrame) => boolean),
 57→    timeoutMs?: number,
 58→  ) => Promise<EventFrame>;
 59→  /** Send a raw text message (for malformed frame testing) */
 60→  readonly sendRaw: (text: string) => void;
 61→  /** Close the WebSocket connection */
 62→  readonly close: () => void;
 63→  /** Whether the connection is open */
 64→  readonly isOpen: () => boolean;
 65→  /** All received frames (for debugging) */
 66→  readonly receivedFrames: readonly GatewayFrame[];
 67→};
 68→
 69→/**
 70→ * Connect to the gateway WebSocket endpoint and return a test client.
 71→ *
 72→ * Uses Bun's built-in WebSocket client. The client automatically parses
 73→ * incoming frames and routes them to pending request promises or event collectors.
 74→ */
 75→export function connectGateway(
 76→  baseUrl: string,
 77→  options?: { connectTimeoutMs?: number },
 78→): Promise<GatewayTestClient> {
 79→  const connectTimeout = options?.connectTimeoutMs ?? 10_000;
 80→
 81→  return new Promise((resolve, reject) => {
 82→    const wsUrl = baseUrl.replace(/^http/, "ws") + "/api/gateway";
 83→
 84→    let ws: WebSocket;
 85→    try {
 86→      ws = new WebSocket(wsUrl);
 87→    } catch (e) {
 88→      return reject(
 89→        new Error(`Gateway WS creation failed: ${(e as Error).message}`),
 90→      );
 91→    }
 92→
 93→    const receivedFrames: GatewayFrame[] = [];
 94→    const pendingRequests = new Map<
 95→      string,
 96→      {
 97→        resolve: (frame: ResponseFrame) => void;
 98→        reject: (err: Error) => void;
 99→      }
100→    >();
101→    const eventListeners: Array<(event: EventFrame) => void> = [];
102→
103→    ws.onmessage = (msg) => {
104→      const frame = JSON.parse(
105→        typeof msg.data === "string" ? msg.data : msg.data.toString(),
106→      ) as GatewayFrame;
107→      receivedFrames.push(frame);
108→
109→      if (frame.type === "res") {
110→        const pending = pendingRequests.get(frame.id);
111→        if (pending) {
112→          pendingRequests.delete(frame.id);
113→          pending.resolve(frame);
114→        }
115→      } else if (frame.type === "event") {
116→        for (const listener of eventListeners) {
117→          listener(frame);
118→        }
119→      }
120→    };
121→
122→    ws.onopen = () => {
123→      const client: GatewayTestClient = {
124→        request: (method, params) => {
125→          const id = crypto.randomUUID();
126→          const frame: RequestFrame = { type: "req", id, method, params };
127→          ws.send(JSON.stringify(frame));
128→
129→          return new Promise((res, rej) => {
130→            const timer = setTimeout(() => {
131→              pendingRequests.delete(id);
132→              rej(
133→                new Error(
134→                  `Gateway request timeout: ${method} (id: ${id}) after 10s`,
135→                ),
136→              );
137→            }, 10_000);
138→
139→            pendingRequests.set(id, {
140→              resolve: (f) => {
141→                clearTimeout(timer);
142→                res(f);
143→              },
144→              reject: (e) => {
145→                clearTimeout(timer);
146→                rej(e);
147→              },
148→            });
149→          });
150→        },
151→
152→        collectEvents: (predicate, timeoutMs = 10_000) => {
153→          return new Promise((res) => {
154→            const collected: EventFrame[] = [];
155→            const timer = setTimeout(() => {
156→              const idx = eventListeners.indexOf(listener);
157→              if (idx >= 0) eventListeners.splice(idx, 1);
158→              res(collected);
159→            }, timeoutMs);
160→
161→            const listener = (event: EventFrame) => {
162→              collected.push(event);
163→              if (predicate(event)) {
164→                clearTimeout(timer);
165→                const idx = eventListeners.indexOf(listener);
166→                if (idx >= 0) eventListeners.splice(idx, 1);
167→                res(collected);
168→              }
169→            };
170→            eventListeners.push(listener);
171→          });
172→        },
173→
174→        waitForEvent: (predicateOrName, timeoutMs = 10_000) => {
175→          const matchFn =
176→            typeof predicateOrName === "string"
177→              ? (e: EventFrame) => e.event === predicateOrName
178→              : predicateOrName;
179→          const label =
180→            typeof predicateOrName === "string"
181→              ? predicateOrName
182→              : "predicate";
183→
184→          return new Promise((res, rej) => {
185→            const timer = setTimeout(() => {
186→              const idx = eventListeners.indexOf(listener);
187→              if (idx >= 0) eventListeners.splice(idx, 1);
188→              rej(
189→                new Error(
190→                  `Gateway event timeout: waiting for "${label}" after ${timeoutMs}ms`,
191→                ),
192→              );
193→            }, timeoutMs);
194→
195→            const listener = (event: EventFrame) => {
196→              if (matchFn(event)) {
197→                clearTimeout(timer);
198→                const idx = eventListeners.indexOf(listener);
199→                if (idx >= 0) eventListeners.splice(idx, 1);
200→                res(event);
201→              }
202→            };
203→            eventListeners.push(listener);
204→          });
205→        },
206→
207→        sendRaw: (text) => ws.send(text),
208→        close: () => ws.close(),
209→        isOpen: () => ws.readyState === WebSocket.OPEN,
210→        receivedFrames,
211→      };
212→
213→      resolve(client);
214→    };
215→
216→    ws.onerror = (err) =>
217→      reject(new Error(`Gateway WS connect failed: ${err}`));
218→
219→    setTimeout(
220→      () => reject(new Error(`Gateway WS connect timeout after ${connectTimeout}ms`)),
221→      connectTimeout,
222→    );
223→  });
224→}
225→
226→/**
227→ * Connect to the gateway and authenticate with a hardcoded skeleton identity.
228→ *
229→ * Walking skeleton mode: the gateway's connect handler recognizes a well-known
230→ * skeleton token ("skeleton-test-token") and transitions directly to active state
231→ * with a hardcoded identity. This lets us test the full pipeline without Ed25519.
232→ *
233→ * This function sends an actual `connect` frame with the skeleton token and waits
234→ * for the `hello-ok` response before returning. If the gateway does not respond
235→ * with ok: true, the test fails immediately (not silently).
236→ *
237→ * For R1+ tests, use Ed25519 auth via connectGatewayWithDeviceAuth().
238→ */
239→export async function connectGatewayWithSkeletonAuth(
240→  baseUrl: string,
241→): Promise<GatewayTestClient> {
242→  const client = await connectGateway(baseUrl);
243→
244→  // Send skeleton connect frame — gateway recognizes the skeleton token
245→  // and bypasses Ed25519 verification, transitioning directly to active.
246→  const connectRes = await client.request("connect", {
247→    minProtocol: 3,
248→    maxProtocol: 3,
249→    client: {
250→      id: "skeleton-test-client",
251→      version: "0.0.0-test",
252→      platform: "test",
253→      mode: "remote",
254→    },
255→    role: "operator",
