{
  "roadmap": {
    "project_id": "openclaw-gateway",
    "created_at": "2026-03-24T14:28:25Z",
    "total_steps": 13,
    "phases": 3
  },
  "phases": [
    {
      "id": "01",
      "name": "Walking Skeleton and Core Types",
      "steps": [
        {
          "id": "01-01",
          "name": "DB migration: agent device fields and openclaw agent_type",
          "criteria": "GIVEN the SurrealDB schema WHEN migration is applied THEN agent table has device_fingerprint, device_public_key, device_platform, device_family fields AND agent_device_fingerprint index exists AND agent_type enum includes 'openclaw'",
          "test_file": "tests/acceptance/gateway/walking-skeleton.test.ts",
          "scenario_name": "WS-5: HTTP GET to /api/gateway returns 426 Upgrade Required"
        },
        {
          "id": "01-02",
          "name": "WebSocket upgrade handler and protocol frame types",
          "criteria": "GIVEN a client sends an HTTP upgrade request to /api/gateway THEN Brain upgrades the connection to WebSocket AND non-upgrade requests receive 426 Upgrade Required AND GatewayFrame discriminated union (RequestFrame | ResponseFrame | EventFrame) with parseFrame/serializeFrame is defined",
          "test_file": "tests/acceptance/gateway/walking-skeleton.test.ts",
          "scenario_name": "WS-1: WebSocket upgrade to /api/gateway succeeds"
        },
        {
          "id": "01-03",
          "name": "Skeleton auth, method dispatch, and agent method handler",
          "criteria": "GIVEN a WebSocket connection with skeleton identity AND workspace has 2 decisions and 1 constraint WHEN client sends agent method THEN Brain responds with runId, sessionId, and contextSummary matching seeded data counts",
          "test_file": "tests/acceptance/gateway/walking-skeleton.test.ts",
          "scenario_name": "WS-2: agent method returns runId with context summary"
        },
        {
          "id": "01-04",
          "name": "Event adapter and token streaming with seq numbers",
          "criteria": "GIVEN an active agent session via the gateway WHEN the orchestrator produces agent_token events THEN the client receives event frames with monotonically increasing seq numbers AND at least one assistant stream event is received",
          "test_file": "tests/acceptance/gateway/walking-skeleton.test.ts",
          "scenario_name": "WS-3: token events stream with monotonically increasing seq numbers"
        },
        {
          "id": "01-05",
          "name": "Session lifecycle completion with done event",
          "criteria": "GIVEN a streaming agent session WHEN the agent finishes execution THEN a lifecycle event with stream 'lifecycle' and phase 'done' is received on the WebSocket",
          "test_file": "tests/acceptance/gateway/walking-skeleton.test.ts",
          "scenario_name": "WS-4: session completes with lifecycle done event"
        }
      ]
    },
    {
      "id": "02",
      "name": "Authentication and Session Management",
      "steps": [
        {
          "id": "02-01",
          "name": "Ed25519 device auth and connect.challenge on WS open",
          "criteria": "GIVEN a client opens a WebSocket to /api/gateway THEN the gateway sends a connect.challenge event within 1 second containing a non-empty base64 nonce and a recent timestamp",
          "test_file": "tests/acceptance/gateway/r1-auth-protocol.test.ts",
          "scenario_name": "R1-1: connect.challenge event sent immediately on WebSocket open"
        },
        {
          "id": "02-02",
          "name": "Full Gateway Protocol v3 connect handshake with identity bridge",
          "criteria": "GIVEN a connect.challenge was received WHEN the client sends a connect frame with Ed25519-signed nonce and device identity THEN the gateway responds with hello-ok containing protocol version 3, tickIntervalMs, deviceToken, and role matching the request",
          "test_file": "tests/acceptance/gateway/r1-auth-protocol.test.ts",
          "scenario_name": "R1-2: Gateway Protocol v3 connect handshake succeeds"
        },
        {
          "id": "02-03",
          "name": "Connection state machine and protocol error handling",
          "criteria": "GIVEN a WebSocket connection WHEN a malformed frame is sent THEN the gateway returns an invalid_frame error AND the connection remains open AND WHEN agent method is sent before authentication THEN not_authenticated error is returned AND WHEN connect is sent while already active THEN already_authenticated error is returned",
          "test_file": "tests/acceptance/gateway/r1-auth-protocol.test.ts",
          "scenario_name": "R1-6: malformed frame returns invalid_frame error"
        },
        {
          "id": "02-04",
          "name": "Known device identity resolution",
          "criteria": "GIVEN a device with a known Ed25519 public key registered in the agent table WHEN it connects and signs the challenge nonce THEN the gateway resolves the existing Brain identity and workspace from the device fingerprint",
          "test_file": "tests/acceptance/gateway/r1-auth-protocol.test.ts",
          "scenario_name": "R1-3: known device resolves Brain identity and workspace"
        },
        {
          "id": "02-05",
          "name": "New device auto-registration via DCR and sessions.list",
          "criteria": "GIVEN a device with an unknown Ed25519 public key WHEN it completes the connect handshake THEN a new agent record is created with device_fingerprint AND an identity record and identity_agent edge are created AND a member_of edge to the default workspace exists AND sessions.list returns sessions for the authenticated identity",
          "test_file": "tests/acceptance/gateway/r1-auth-protocol.test.ts",
          "scenario_name": "R1-4: new device auto-registers via DCR"
        }
      ]
    },
    {
      "id": "03",
      "name": "Governance and Discovery",
      "steps": [
        {
          "id": "03-01",
          "name": "Presence tracking and broadcast",
          "criteria": "GIVEN two authenticated gateway connections WHEN both are active THEN a presence query returns at least 2 online devices with deviceFingerprint, status 'online', and agentType fields",
          "test_file": "tests/acceptance/gateway/r3-governance.test.ts",
          "scenario_name": "R3-3: presence query returns online devices"
        },
        {
          "id": "03-02",
          "name": "Model listing without API key exposure",
          "criteria": "GIVEN an authenticated gateway connection WHEN client sends model.list THEN the response contains at least 1 model with id and provider fields AND the serialized response does not contain 'sk-', 'api_key', or 'apiKey' strings",
          "test_file": "tests/acceptance/gateway/r3-governance.test.ts",
          "scenario_name": "R3-5: model.list returns configured models without API keys"
        },
        {
          "id": "03-03",
          "name": "Tools catalog and config.get discovery methods",
          "criteria": "GIVEN an authenticated gateway connection WHEN client sends tools.catalog THEN the response contains an array of tools with name, description, and server fields AND WHEN client sends config.get THEN the response contains gateway version, protocol 3, features array, and tickIntervalMs AND WHEN client sends an unsupported method THEN method_not_supported error is returned",
          "test_file": "tests/acceptance/gateway/r2-execution.test.ts",
          "scenario_name": "R2-12: config.get returns read-only gateway configuration"
        }
      ]
    }
  ],
  "implementation_scope": {
    "source_directories": [
      "app/src/server/gateway/"
    ],
    "test_directories": [
      "tests/acceptance/gateway/",
      "tests/unit/gateway/"
    ],
    "excluded_patterns": [
      "**/*.md",
      "**/*.feature"
    ]
  },
  "validation": {
    "status": "approved",
    "reviewer": "morgan-sa",
    "approved_at": "2026-03-24T15:00:00Z"
  }
}

