  1→/**
  2→ * Gateway Protocol v3 — Frame types, parsing, and serialization.
  3→ *
  4→ * All functions are pure. No IO, no side effects, no imports from IO modules.
  5→ * The protocol uses JSON text frames over WebSocket with three discriminants:
  6→ * - "req"   — client-to-server request expecting a response
  7→ * - "res"   — server-to-client response matching a request id
  8→ * - "event" — server-to-client push notification (no request id needed)
  9→ */
 10→
 11→// ---------------------------------------------------------------------------
 12→// Method names — all protocol methods the gateway recognizes
 13→// ---------------------------------------------------------------------------
 14→
 15→export type MethodName =
 16→  | "connect"
 17→  | "ping"
 18→  | "agent"
 19→  | "session.list"
 20→  | "session.history"
 21→  | "session.patch"
 22→  | "context.load"
 23→  | "tools.list"
 24→  | "tools.grant";
 25→
 26→// ---------------------------------------------------------------------------
 27→// Error codes — protocol-level and business-level error classifications
 28→// ---------------------------------------------------------------------------
 29→
 30→export type ErrorCode =
 31→  | "PARSE_ERROR"
 32→  | "INVALID_PARAMS"
 33→  | "METHOD_NOT_FOUND"
 34→  | "AUTH_FAILED"
 35→  | "AUTH_REQUIRED"
 36→  | "FORBIDDEN"
 37→  | "NOT_FOUND"
 38→  | "RATE_LIMITED"
 39→  | "INTERNAL_ERROR"
 40→  | "PROTOCOL_MISMATCH"
 41→  | "CONNECTION_CLOSED";
 42→
 43→// ---------------------------------------------------------------------------
 44→// Frame types — discriminated union on the "type" field
 45→// ---------------------------------------------------------------------------
 46→
 47→export type RequestFrame = {
 48→  readonly type: "req";
 49→  readonly id: string;
 50→  readonly method: MethodName;
 51→  readonly params?: unknown;
 52→};
 53→
 54→export type GatewayError = {
 55→  readonly code: ErrorCode;
 56→  readonly message: string;
 57→  readonly details?: unknown;
 58→};
 59→
 60→export type ResponseFrame =
 61→  | {
 62→      readonly type: "res";
 63→      readonly id: string;
 64→      readonly ok: true;
 65→      readonly payload?: unknown;
 66→    }
 67→  | {
 68→      readonly type: "res";
 69→      readonly id: string;
 70→      readonly ok: false;
 71→      readonly error: GatewayError;
 72→    };
 73→
 74→export type EventFrame = {
 75→  readonly type: "event";
 76→  readonly event: string;
 77→  readonly payload?: unknown;
 78→  readonly seq?: number;
 79→};
 80→
 81→export type GatewayFrame = RequestFrame | ResponseFrame | EventFrame;
 82→
 83→// ---------------------------------------------------------------------------
 84→// Pure parser — string to GatewayFrame | { error: string }
 85→// ---------------------------------------------------------------------------
 86→
 87→export type ParseError = { readonly parseError: string };
 88→
 89→export function parseFrame(raw: string): GatewayFrame | ParseError {
 90→  let parsed: unknown;
 91→  try {
 92→    parsed = JSON.parse(raw);
 93→  } catch {
 94→    return { parseError: "Failed to parse JSON frame" };
 95→  }
 96→
 97→  if (typeof parsed !== "object" || parsed === null) {
 98→    return { parseError: "Frame must be a JSON object" };
 99→  }
100→
101→  const obj = parsed as Record<string, unknown>;
102→  const frameType = obj.type;
103→
104→  if (frameType === "req") {
105→    return parseRequestFrame(obj);
106→  }
107→  if (frameType === "res") {
108→    return parseResponseFrame(obj);
109→  }
110→  if (frameType === "event") {
111→    return parseEventFrame(obj);
112→  }
113→
114→  return { parseError: `Unknown frame type: ${String(frameType)}` };
115→}
116→
117→export function isParseError(result: GatewayFrame | ParseError): result is ParseError {
118→  return "parseError" in result;
119→}
120→
121→function parseRequestFrame(obj: Record<string, unknown>): RequestFrame | ParseError {
122→  if (typeof obj.id !== "string") {
123→    return { parseError: "Request frame missing required field: id" };
124→  }
125→  if (typeof obj.method !== "string") {
126→    return { parseError: "Request frame missing required field: method" };
127→  }
128→  const frame: RequestFrame = {
129→    type: "req",
130→    id: obj.id,
131→    method: obj.method as MethodName,
132→    ...(obj.params !== undefined ? { params: obj.params } : {}),
133→  };
134→  return frame;
135→}
136→
137→function parseResponseFrame(obj: Record<string, unknown>): ResponseFrame | ParseError {
138→  if (typeof obj.id !== "string") {
139→    return { parseError: "Response frame missing required field: id" };
140→  }
141→  if (typeof obj.ok !== "boolean") {
142→    return { parseError: "Response frame missing required field: ok" };
143→  }
144→
145→  if (obj.ok) {
146→    const frame: ResponseFrame = {
147→      type: "res",
148→      id: obj.id,
149→      ok: true,
150→      ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
151→    };
152→    return frame;
153→  }
154→
155→  const frame: ResponseFrame = {
156→    type: "res",
157→    id: obj.id,
158→    ok: false,
159→    error: obj.error as GatewayError,
160→  };
161→  return frame;
162→}
163→
164→function parseEventFrame(obj: Record<string, unknown>): EventFrame | ParseError {
165→  if (typeof obj.event !== "string") {
166→    return { parseError: "Event frame missing required field: event" };
167→  }
168→  const frame: EventFrame = {
169→    type: "event",
170→    event: obj.event,
171→    ...(obj.payload !== undefined ? { payload: obj.payload } : {}),
172→    ...(obj.seq !== undefined ? { seq: obj.seq as number } : {}),
173→  };
174→  return frame;
175→}
176→
177→// ---------------------------------------------------------------------------
178→// Pure serializer — GatewayFrame to JSON string
179→// ---------------------------------------------------------------------------
180→
181→export function serializeFrame(frame: GatewayFrame): string {
182→  return JSON.stringify(frame);
183→}
184→

